CREATE TABLE `contract_mdm2_devices` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `contract_cd` varchar(25) NOT NULL COMMENT '契約CD',
  `contract_status_cd` varchar(1) NOT NULL COMMENT '契約ステータスCD',
  `unis_customer_cd` varchar(32) NOT NULL COMMENT 'UNIS顧客CD(設置先CD)',
  `neos_item_pac_cd` varchar(14) NOT NULL COMMENT 'NeOS親パック品目CD',
  `neos_item_pac_name` varchar(100) NOT NULL COMMENT 'NeOS親パック品目名',
  `neos_item_cd` varchar(14) NOT NULL COMMENT 'NeOS品目CD',
  `neos_item_name` varchar(100) NOT NULL COMMENT 'NeOS品目名',
  `option1_contract_cd` varchar(25) DEFAULT NULL COMMENT 'オプション1_契約CD',
  `option1_contract_status_cd` varchar(1) DEFAULT NULL COMMENT 'オプション1_契約ステータスCD',
  `option1_neos_item_cd` varchar(14) DEFAULT NULL COMMENT 'オプション1_NeOS品目CD',
  `option2_contract_cd` varchar(25) DEFAULT NULL COMMENT 'オプション2_契約CD',
  `option2_contract_status_cd` varchar(1) DEFAULT NULL COMMENT 'オプション2_契約ステータスCD',
  `option2_neos_item_cd` varchar(14) DEFAULT NULL COMMENT 'オプション2_NeOS品目CD',
  `option3_contract_cd` varchar(25) DEFAULT NULL COMMENT 'オプション3_契約CD',
  `option3_contract_status_cd` varchar(1) DEFAULT NULL COMMENT 'オプション3_契約ステータスCD',
  `option3_neos_item_cd` varchar(14) DEFAULT NULL COMMENT 'オプション3_NeOS品目CD',
  `option4_contract_cd` varchar(25) DEFAULT NULL COMMENT 'オプション4_契約CD',
  `option4_contract_status_cd` varchar(1) DEFAULT NULL COMMENT 'オプション4_契約ステータスCD',
  `option4_neos_item_cd` varchar(14) DEFAULT NULL COMMENT 'オプション4_NeOS品目CD',
  `option5_contract_cd` varchar(25) DEFAULT NULL COMMENT 'オプション5_契約CD',
  `option5_contract_status_cd` varchar(1) DEFAULT NULL COMMENT 'オプション5_契約ステータスCD',
  `option5_neos_item_cd` varchar(14) DEFAULT NULL COMMENT 'オプション5_NeOS品目CD',
  `create_date` datetime DEFAULT NULL,
  `renewal_date` datetime DEFAULT NULL,
  `com_ssid1_name` varchar(25) NOT NULL COMMENT 'SSID1(UT+顧客コード+001)',
  `com_ssid1_pass` varchar(16) NOT NULL COMMENT 'SSID1 パスワード値(ES3O8DF+顧客コード)',
  `umembers_key` varchar(32) DEFAULT NULL COMMENT 'U-FAX 番号アカウントキー',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime NOT NULL ON UPDATE CURRENT_TIMESTAMP,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3163 DEFAULT CHARSET=utf8mb4 COMMENT='U∞タブレットMDM2情報';
